test('rejects conjunction-linked topic clauses when one segment implies more than one topic summary', () => {
  const sourceResponse = [
    'Auth strategy should use Bun-native auth',
    'and rollout strategy should use a staged rollout for pilot scope.',
  ].join(' ')

  expect(() =>
    materializeInterpretedDecisionAnswerBatch(
      [],
      [],
      false,
      sourceResponse,
      [],
      'topic_clauses',
      undefined,
      true,
    ),
  ).toThrow(
    'Multiple topic clause anchors matched conjunction segment "rollout strategy should use a staged rollout for pilot scope." in sourceResponse.',
  )
})

