test('auto sourceResponseFormat skips inline topics when prefixed topic sentences establish stronger topic authority', () => {
  const sourceResponse = [
    'For auth strategy, use Bun-native auth.',
    'And about rollout strategy, use a staged rollout.',
    'And about pilot scope, start with five enterprise customers before broader launch.',
  ].join(' ')

  const resolvedFormat = resolveAutoSourceResponseFormat(
    'auto',
    listAutoSourceResponseFormatCandidates({
      hasSourceResponse: true,
      hasAnswerSources: false,
      needsExplicitAnswerInterpretation: false,
      inferDecisionTopics: true,
      sourceResponse,
    }),
    (candidateFormat) => {
      const state = createInterpretedSourceResponseState(sourceResponse, candidateFormat)
      materializeInterpretedDecisionAnswerBatch(
        [],
        [],
        false,
        sourceResponse,
        [],
        candidateFormat,
        state,
        true,
        [],
        ['Pilot scope'],
      )
    },
    'inferDecisionTopics',
  )

  expect(resolvedFormat).toBe('topic_spans')

  expect(
    materializeInterpretedDecisionAnswerBatch(
      [],
      [],
      false,
      sourceResponse,
      [],
      resolvedFormat,
      undefined,
      true,
      [],
      ['Pilot scope'],
    ),
  ).toEqual([
    {
      decisionKey: undefined,
      summary: 'Auth strategy',
      prompt: 'What should the auth strategy be?',
      taskRef: undefined,
      answer: 'For auth strategy, use Bun-native auth.',
    },
    {
      decisionKey: undefined,
      summary: 'Rollout strategy',
      prompt: 'What should the rollout strategy be?',
      taskRef: undefined,
      answer: 'And about rollout strategy, use a staged rollout.',
    },
  ])
})

