test('auto sourceResponseFormat rejects weaker ordered-block fallback when malformed question paragraph authority remains for inferOpenDecisions', () => {
  const sourceResponse = [
    'Use Bun-native auth. What should rollout strategy be?',
    '',
    'What should auth strategy be?',
    '',
    'Use a staged rollout.',
    '',
    'What should rollout strategy be?',
  ].join('\n')

  expect(() =>
    materializeInterpretedDecisionBundle({
      answers: [],
      openDecisions: [
        {
          decisionKey: 'auth-strategy',
          summary: 'Choose the auth strategy',
          prompt: 'What should auth strategy be?',
        },
      ],
      inferOpenDecisions: true,
      sourceResponse,
      sourceResponseFormat: 'auto',
    }),
  ).toThrow(
    'sourceResponseFormat auto could not deterministically match decision answer bundle. Provide an explicit sourceResponseFormat. Last probe error: Question clause "Use Bun-native auth. What should rollout strategy be?" in sourceResponse did not include answer text.',
  )
})

