test('materializes new decision topics from one continuous question-opening sentence by inferred canonical question anchors while reserving planner summaries', () => {
  const sourceResponse = [
    'What should auth strategy be use Bun-native auth because that keeps the runtime simple',
    'what should rollout strategy be use a staged rollout because that keeps rollback simple',
    'what should pilot scope be start with five enterprise customers before broader launch.',
  ].join(' ')

  expect(
    materializeInterpretedDecisionAnswerBatch(
      [],
      [],
      false,
      sourceResponse,
      [],
      'question_spans',
      undefined,
      true,
      [],
      ['Pilot scope'],
    ),
  ).toEqual([
    {
      summary: 'Auth strategy',
      prompt: 'What should the auth strategy be?',
      decisionKey: undefined,
      taskRef: undefined,
      answer: 'use Bun-native auth because that keeps the runtime simple',
    },
    {
      summary: 'Rollout strategy',
      prompt: 'What should the rollout strategy be?',
      decisionKey: undefined,
      taskRef: undefined,
      answer: 'use a staged rollout because that keeps rollback simple',
    },
  ])
})

test('auto sourceResponseFormat selects question spans across one continuous sentence when inferred canonical question anchors establish new decision topics', () => {
  const sourceResponse = [
    'What should auth strategy be use Bun-native auth because that keeps the runtime simple',
    'what should rollout strategy be use a staged rollout because that keeps rollback simple.',
  ].join(' ')

  const materialized = materializeInterpretedDecisionBundle({
    sourceResponse,
    sourceResponseFormat: 'auto',
    answers: [],
    openDecisions: [],
    inferOpenDecisions: false,
    inferDecisionTopics: true,
    knownDecisions: [],
  })

  expect(materialized.sourceResponseFormat).toBe('question_spans')
  expect(materialized.answers).toEqual([
    {
      summary: 'Auth strategy',
      prompt: 'What should the auth strategy be?',
      decisionKey: undefined,
      taskRef: undefined,
      matchHints: undefined,
      answer: 'use Bun-native auth because that keeps the runtime simple',
    },
    {
      summary: 'Rollout strategy',
      prompt: 'What should the rollout strategy be?',
      decisionKey: undefined,
      taskRef: undefined,
      matchHints: undefined,
      answer: 'use a staged rollout because that keeps rollback simple.',
    },
  ])
})

