test('auto sourceResponseFormat selects question middle spans across one continuous sentence when question anchors stay explicit', () => {
  const sourceResponse =
    'Keep the runtime simple before what should auth strategy be use Bun-native auth after review.'
  const resolvedFormat = resolveAutoSourceResponseFormat(
    'auto',
    listAutoSourceResponseFormatCandidates({
      hasSourceResponse: true,
      hasAnswerSources: false,
      needsExplicitAnswerInterpretation: false,
      inferOpenDecisions: true,
    }),
    (candidateFormat) => {
      const state = createInterpretedSourceResponseState(sourceResponse, candidateFormat)
      materializeInterpretedDecisionAnswerBatch(
        [],
        [
          {
            decisionKey: 'auth-strategy',
            summary: 'Choose the auth strategy',
            prompt: 'What should auth strategy be?',
          },
        ],
        true,
        sourceResponse,
        [],
        candidateFormat,
        state,
        false,
        [],
        [],
      )
    },
    'inferOpenDecisions',
  )

  expect(resolvedFormat).toBe('question_middle_spans')

  expect(
    materializeInterpretedDecisionAnswerBatch(
      [],
      [
        {
          decisionKey: 'auth-strategy',
          summary: 'Choose the auth strategy',
          prompt: 'What should auth strategy be?',
        },
      ],
      true,
      sourceResponse,
      [],
      resolvedFormat,
    ),
  ).toEqual([
    {
      decisionKey: 'auth-strategy',
      summary: 'Choose the auth strategy',
      taskRef: undefined,
      answer: 'Keep the runtime simple before use Bun-native auth after review.',
    },
  ])
})

