test('single pending rejects explicit decision answers when answer starts with a non-punctuated adverb-led existential plural-complement question fragment', () => {
  for (const sourceResponse of [
    'Why there are rollout blockers.',
    'Why there need to be rollout blockers.',
    'Where there have been rollout blockers.',
    'When there would be rollout blockers.',
  ]) {
    expect(() =>
      materializeInterpretedDecisionBundle({
        sourceResponse,
        sourceResponseFormat: 'single_pending',
        answers: [
          {
            summary: 'Rollout strategy',
            prompt: 'Should rollout happen in stages or all at once?',
          },
        ],
        openDecisions: [],
        inferOpenDecisions: false,
        inferDecisionTopics: false,
      }),
    ).toThrow(
      `Single pending reply for decision answer Rollout strategy in sourceResponse included answer text with question authority "${sourceResponse.replace(/\.$/, '?')}".`,
    )
  }
})

